adtostudy.com/#person"},"inLanguage":"tr"},{"@type":"WebPage","@id":"https://roadtostudy.com/turkiyede-taciz-siddet-yasal-haklar/#webpage","url":"https://roadtostudy.com/turkiyede-taciz-siddet-yasal-haklar/","name":"Türkiye&#039;de Taciz ve Şiddetle Mücadele Yasal Haklar","datePublished":"2025-10-06T17:23:16+03:00","dateModified":"2026-03-15T21:40:34+03:00","isPartOf":{"@id":"https://roadtostudy.com/#website"},"inLanguage":"tr"},{"@type":"Person","@id":"https://roadtostudy.com/author/murat/","name":"Murat","url":"https://roadtostudy.com/author/murat/","image":{"@type":"ImageObject","@id":"https://secure.gravatar.com/avatar/9f5b866231ae7aed7a61015846c1f0ab6c5797b065ec200b93c5e9daa87897af?s=96&amp;d=mm&amp;r=g","url":"https://secure.gravatar.com/avatar/9f5b866231ae7aed7a61015846c1f0ab6c5797b065ec200b93c5e9daa87897af?s=96&amp;d=mm&amp;r=g","caption":"Murat","inLanguage":"tr"}},{"@type":"BlogPosting","headline":"Türkiye&#039;de Taciz ve Şiddetle Mücadele Yasal Haklar","keywords":"taciz ve şiddet","datePublished":"2025-10-06T17:23:16+03:00","dateModified":"2026-03-15T21:40:34+03:00","articleSection":"Sağlık ve Güvenlik","author":{"@id":"https://roadtostudy.com/author/murat/","name":"Murat"},"publisher":{"@id":"https://roadtostudy.com/#person"},"description":"Taciz ve şiddete karşı yasal haklarınızı öğrenin. Bilgi edinin, haklarınızı savunun ve destek alın!","name":"Türkiye&#039;de Taciz ve Şiddetle Mücadele Yasal Haklar","@id":"https://roadtostudy.com/turkiyede-taciz-siddet-yasal-haklar/#richSnippet","isPartOf":{"@id":"https://roadtostudy.com/turkiyede-taciz-siddet-yasal-haklar/#webpage"},"inLanguage":"tr","mainEntityOfPage":{"@id":"https://roadtostudy.com/turkiyede-taciz-siddet-yasal-haklar/#webpage"}}]}]}', "content_html" = '<p class="wp-block-paragraph">Türkiye, kadınların ve diğer mağdurların taciz ve şiddet gibi sorunlarla başa çıkabilmesi için çeşitli yasal haklar ve koruma yöntemleri sunmaktadır. Bu makalede, Türkiye&#8217;deki yasal haklarınızı, 6284 sayılı kanunun ne anlama geldiğini, taciz ve şiddetle mücadeledeki yasal süreçleri, Türkiye&#8217;deki kadın haklarını ve kadına yönelik şiddetin türlerini detaylı bir şekilde inceleyeceğiz.</p>
<h2 id="yasal-haklariniz-turkiyede-taciz-ve-siddete-karsi-koruma-yontemleri" class="wp-block-heading">Yasal Haklarınız: Türkiye&#8217;de Taciz ve Şiddete Karşı Koruma Yöntemleri</h2>
<p class="wp-block-paragraph">Türkiye&#8217;de, taciz ve şiddet mağdurlarının korunması için bir dizi yasal hak ve koruma yöntemi bulunmaktadır. Bu haklar, mağdurların güvenliğini sağlamak ve adalet arayışlarını desteklemek amacıyla oluşturulmuştur.</p>
<h3 class="wp-block-heading">Koruma Kararları</h3>
<p class="wp-block-paragraph">Taciz veya şiddet mağdurları, mahkemeden koruma talep edebilirler. Koruma kararları, mağdurun güvenliğini sağlamak için çeşitli önlemler içermektedir. Bu önlemler arasında:</p>
<ul class="wp-block-list">
<li>Mağdurun bulunduğu yere yaklaşmanın yasaklanması</li>
<li>İletişimin engellenmesi</li>
<li>Geçici olarak barınma yerinin değiştirilmesi</li>
</ul>
<p class="wp-block-paragraph">gibi tedbirler yer alır. Bu kararlar, mağdurun güvenliğini sağlamak amacıyla hızlı bir şekilde alınabilir.</p>
<h3 class="wp-block-heading">Şikayet Hakkı</h3>
<p class="wp-block-paragraph">Taciz veya şiddet mağdurları, yaşadıkları durumu polise bildirme hakkına sahiptir. Bu, mağdurların yasal süreç başlatmalarını ve faillerin cezalandırılmasını sağlamaktadır.</p>
<h2 id="6284-sayili-kanun-ne-diyor" class="wp-block-heading">6284 Sayılı Kanun Ne Diyor?</h2>
<p class="wp-block-paragraph">6284 sayılı kanun, Türkiye&#8217;de <a href="https://roadtostudy.com/turkiyede-kadin-guvenligi-onlemler/">kadına yönelik şiddetle</a> mücadele ve aile içi şiddetin önlenmesine yönelik önemli bir yasadır. Bu kanun, mağdurların korunmasını ve desteklenmesini amaçlamaktadır.</p>
<h3 class="wp-block-heading">Kanunun Kapsamı</h3>
<p class="wp-block-paragraph">6284 sayılı kanun, sadece kadınları değil, çocukları ve diğer aile bireylerini de kapsamaktadır. Bu kanun kapsamında, şiddet mağdurlarına yönelik şu haklar tanınmaktadır:</p>
<ul class="wp-block-list">
<li>Koruma tedbirleri</li>
<li>Psiko-sosyal destek</li>
<li>Barınma hizmetleri</li>
</ul>
<p class="wp-block-paragraph">Bu haklar, mağdurların güvenliğini sağlamak ve yeniden hayata adapte olmalarına yardımcı olmak amacıyla sunulmaktadır.</p>
<h2 id="turkiyede-taciz-ve-siddetle-mucadelede-yasal-surecler" class="wp-block-heading">Türkiye&#8217;de Taciz ve Şiddetle Mücadelede Yasal Süreçler</h2>
<p class="wp-block-paragraph">Türkiye&#8217;de taciz ve şiddetle mücadelede izlenmesi gereken yasal süreçler, mağdurların haklarını koruma amacı taşımaktadır.</p>
<h3 class="wp-block-heading">Şikayet Süreci</h3>
<p class="wp-block-paragraph">Taciz veya şiddet olayları, öncelikle polise bildirilmelidir. Şikayet süreci şu adımları içermektedir:</p>
<ul class="wp-block-list">
<li><strong>Olayın Bildirilmesi:</strong> Mağdur, yaşadığı durumu en yakın polis karakoluna veya jandarmaya bildirmelidir.</li>
<li><strong>İfade Alma:</strong> Polis, mağdurdan olayla ilgili detaylı bilgi alır ve bir ifade tutanağı hazırlar.</li>
<li><strong>Soruşturma:</strong> Polisin, şikayeti değerlendirmesi ve gerekli soruşturmaları yapması beklenir.</li>
<li><strong>Mahkemeye Başvuru:</strong> Mağdur, gerekli görürse mahkemeye başvurarak koruma talep edebilir.</li>
</ul>
<h3 class="wp-block-heading">Mahkeme Süreci</h3>
<p class="wp-block-paragraph">Eğer mağdur, koruma talebinde bulunursa, mahkeme süreci başlar. Mahkeme, mağdurun taleplerini değerlendirir ve gerekli koruma kararlarını alır.</p>
<h2 id="turkiyedeki-kadin-haklari-nelerdir" class="wp-block-heading">Türkiye&#8217;deki Kadın Hakları Nelerdir?</h2>
<p class="wp-block-paragraph">Türkiye&#8217;de kadın hakları, çeşitli yasalarla güvence altına alınmıştır. Bu haklar, kadınların toplumsal hayatta daha aktif rol almasını ve eşit haklara sahip olmasını sağlamaktadır.</p>
<h3 class="wp-block-heading">Temel Haklar</h3>
<p class="wp-block-paragraph">Kadınların sahip olduğu temel haklar arasında:</p>
<ul class="wp-block-list">
<li>Eğitim hakkı</li>
<li>Çalışma hakkı</li>
<li>Sağlık hizmetlerinden yararlanma hakkı</li>
<li>Seçme ve seçilme hakkı</li>
</ul>
<p class="wp-block-paragraph">yer almaktadır. Bu haklar, kadınların toplumsal hayatta eşit bireyler olarak yer almasını sağlamaktadır.</p>
<h2 id="sik-sorulan-sorular-faq" class="wp-block-heading">Sık Sorulan Sorular (FAQ)</h2>
<h3 class="wp-block-heading">Türkiye&#8217;de taciz ve şiddet durumunda ne yapmalıyım?</h3>
<p class="wp-block-paragraph">Taciz veya şiddet durumunda, en yakın polis karakoluna başvurmalı ve durumu bildirmelisiniz. Ayrıca, mahkemeden koruma talep edebilirsiniz.</p>
<h3 class="wp-block-heading">6284 sayılı kanun kimleri kapsıyor?</h3>
<p class="wp-block-paragraph">6284 sayılı kanun, kadınları, çocukları ve aile bireylerini kapsamaktadır. Şiddet mağdurlarına yönelik koruma tedbirleri sunmaktadır.</p>
<h3 class="wp-block-heading">Koruma kararı almak ne kadar sürer?</h3>
<p class="wp-block-paragraph">Koruma kararı almak, genellikle hızlı bir süreçtir. Mahkeme, başvurunuzun ardından en kısa sürede karar vermeye çalışır.</p>
<h3 class="wp-block-heading">Kadın hakları nelerdir?</h3>
<p class="wp-block-paragraph">Kadın hakları arasında eğitim, çalışma, sağlık hizmetlerinden yararlanma ve seçme-seçilme hakları bulunmaktadır.</p>', "wp_published_at" = '2025-10-06T14:23:16Z', "wp_modified_at" = '2026-03-15T18:40:34Z' WHERE "deleted_at" IS NULL AND "status" = 'published' AND "locale" = 'tr' AND "slug" = 'turkiyede-taciz-siddet-yasal-haklar';
